if (self::FORMAT_JSON === $format) {
    $json = ['advisories' => $advisories];
    if ($ignoredAdvisories !== []) {
        $json['ignored-advisories'] = $ignoredAdvisories;
    }
    if ($unreachableRepos !== []) {
        $json['unreachable-repositories'] = $unreachableRepos;
    }
    $json['abandoned'] = array_reduce($abandonedPackages, static function (array $carry, CompletePackageInterface $package): array {
        $carry[$package->getPrettyName()] = $package->getReplacementPackage();

        return $carry;
    }, []);
    $json['filter'] = array_map(static function (array $entries) {
        return array_map(static function (FilterListEntry $entry) {
            $data = (array) $entry;
            $data['constraint'] = $entry->constraint->getPrettyString();

            return $data;
        }, $entries);
    }, $filteredPackages);

    $io->write(JsonFile::encode($json));

    return $auditResult;
}

if (Preg::isMatch('{^(bitbucket-oauth|github-oauth|gitlab-oauth|gitlab-token|bearer|http-basic|custom-headers|forgejo-token|platform)\.}', $key)) {
    [$key, $host] = explode('.', $key, 2);
    if ($authConfig) {
        $config[$key][$host] = $val;
    } else {
        $config['config'][$key][$host] = $val;
    }
} elseif (strpos($key, 'policy.') === 0) {
    if (!isset($config['config']) || !is_array($config['config'])) {
        $config['config'] = [];
    }

    $bits = explode('.', $key);
    $last = array_pop($bits);
    $arr = &$config['config'];
    foreach ($bits as $bit) {
        if (!isset($arr[$bit]) || !is_array($arr[$bit])) {
            $arr[$bit] = [];
        }
        $arr = &$arr[$bit];
    }
    $arr[$last] = $val;
} else {
    $config['config'][$key] = $val;
}

if ($dh = opendir($dir)) {
    while ($file = readdir($dh)) {
        if ($file !== '.' && $file !== '..') {
            if (is_link($dir.'/'.$file)) {
                $array[$dir][$file] = readlink($dir.'/'.$file);
            } elseif (is_dir($dir.'/'.$file)) {
                if (!count($array)) {
                    $array[0] = 'Temp';
                }
                if (!$this->doTree($dir.'/'.$file, $array)) {
                    return false;
                }
            } elseif (is_file($dir.'/'.$file) && filesize($dir.'/'.$file)) {
                $array[$dir][$file] = hash_file(\PHP_VERSION_ID > 80100 ? 'xxh3' : 'sha1', $dir.'/'.$file);
            }
        }
    }
    if (count($array) > 1 && isset($array['0'])) {
        unset($array['0']);
    }

    return $array;
}

if (null === $this->branches) {
    $branches = [];
    $bookmarks = [];

    $this->process->execute(['hg', 'branches'], $output, $this->repoDir);
    foreach ($this->process->splitLines($output) as $branch) {
        if ($branch && Preg::isMatchStrictGroups('(^([^\s]+)\s+\d+:([a-f0-9]+))', $branch, $match) && $match[1][0] !== '-') {
            $branches[$match[1]] = $match[2];
        }
    }

    $this->process->execute(['hg', 'bookmarks'], $output, $this->repoDir);
    foreach ($this->process->splitLines($output) as $branch) {
        if ($branch && Preg::isMatchStrictGroups('(^(?:[\s*]*)([^\s]+)\s+\d+:(.*)$)', $branch, $match) && $match[1][0] !== '-') {
            $bookmarks[$match[1]] = $match[2];
        }
    }

    // Branches will have preference over bookmarks
    $this->branches = array_merge($bookmarks, $branches);
}

if (null === $this->tags) {
    $tags = [];

    if ($this->tagsPath !== false) {
        $output = $this->execute(['svn', 'ls', '--verbose'], $this->baseUrl . '/' . $this->tagsPath);
        if ($output !== '') {
            $lastRev = 0;
            foreach ($this->process->splitLines($output) as $line) {
                $line = trim($line);
                if ($line !== '' && Preg::isMatch('{^\s*(\S+).*?(\S+)\s*$}', $line, $match)) {
                    if ($match[2] === './') {
                        $lastRev = (int) $match[1];
                    } else {
                        $tags[rtrim($match[2], '/')] = $this->buildIdentifier(
                            '/' . $this->tagsPath . '/' . $match[2],
                            max($lastRev, (int) $match[1])
                        );
                    }
                }
            }
        }
    }

    $this->tags = $tags;
}

if (!@mkdir($directory, 0777, true)) {
    $e = new \RuntimeException($directory.' does not exist and could not be created: '.(error_get_last()['message'] ?? ''));

    // in pathological cases with paths like path/to/broken-symlink/../foo is_dir will fail to detect path/to/foo
    // but normalizing the ../ away first makes it work so we attempt this just in case, and if it still fails we
    // report the initial error we had with the original path, and ignore the normalized path exception
    // see https://github.com/composer/composer/issues/11864
    $normalized = $this->normalizePath($directory);
    if ($normalized !== $directory) {
        try {
            $this->ensureDirectoryExists($normalized);

            return;
        } catch (\Throwable $ignoredEx) {
        }
    }

    throw $e;
}

if (!is_dir($source)) {
    try {
        return copy($source, $target);
    } catch (ErrorException $e) {
        // if copy fails we attempt to copy it manually as this can help bypass issues with VirtualBox shared folders
        // see https://github.com/composer/composer/issues/12057
        if (str_contains($e->getMessage(), 'Bad address')) {
            $sourceHandle = fopen($source, 'r');
            $targetHandle = fopen($target, 'w');
            if (false === $sourceHandle || false === $targetHandle) {
                throw $e;
            }
            while (!feof($sourceHandle)) {
                if (false === fwrite($targetHandle, (string) fread($sourceHandle, 1024 * 1024))) {
                    throw $e;
                }
            }
            fclose($sourceHandle);
            fclose($targetHandle);

            return true;
        }
        throw $e;
    }
}

foreach ($tempCollectorErrors as $tempCollectorError) {
	$file = $tempCollectorError->getTraitFilePath() ?? $tempCollectorError->getFilePath();
	$linesToIgnore = $allLinesToIgnore[$file] ?? [];
	$unmatchedLineIgnores = $allUnmatchedLineIgnores[$file] ?? [];
	$localIgnoresProcessorResult = $this->localIgnoresProcessor->process(
		[$tempCollectorError],
		$linesToIgnore,
		$unmatchedLineIgnores,
	);
	foreach ($localIgnoresProcessorResult->getFileErrors() as $error) {
		$errors[] = $error;
		$collectorErrors[] = $error;
	}
	foreach ($localIgnoresProcessorResult->getLocallyIgnoredErrors() as $locallyIgnoredError) {
		$locallyIgnoredErrors[] = $locallyIgnoredError;
		$locallyIgnoredCollectorErrors[] = $locallyIgnoredError;
	}
	$allLinesToIgnore[$file] = $localIgnoresProcessorResult->getLinesToIgnore();
	$allUnmatchedLineIgnores[$file] = $localIgnoresProcessorResult->getUnmatchedLineIgnores();
}

foreach ($clonePropertiesArgTypeConstantArrays as $clonePropertiesArgTypeConstantArray) {
	foreach ($clonePropertiesArgTypeConstantArray->getKeyTypes() as $i => $clonePropertyKeyType) {
		$clonePropertyKeyTypeScalars = $clonePropertyKeyType->getConstantScalarValues();
		$propertyAttributes = $normalizedExpr->getAttributes();
		$propertyAttributes['inCloneWith'] = true;
		if (count($clonePropertyKeyTypeScalars) === 1) {
			$nodeScopeResolver->processVirtualAssign(
				$scope,
				$storage,
				$stmt,
				new PropertyFetch($cloneExpr, (string) $clonePropertyKeyTypeScalars[0], $propertyAttributes),
				new TypeExpr($clonePropertiesArgTypeConstantArray->getValueTypes()[$i]),
				$nodeCallback,
			);
			continue;
		}

		$nodeScopeResolver->processVirtualAssign(
			$scope,
			$storage,
			$stmt,
			new PropertyFetch($cloneExpr, new TypeExpr($clonePropertyKeyType), $propertyAttributes),
			new TypeExpr($clonePropertiesArgTypeConstantArray->getValueTypes()[$i]),
			$nodeCallback,
		);
	}
}

foreach ($clonePropertiesArgTypeConstantArray->getKeyTypes() as $i => $clonePropertyKeyType) {
	$clonePropertyKeyTypeScalars = $clonePropertyKeyType->getConstantScalarValues();
	$propertyAttributes = $normalizedExpr->getAttributes();
	$propertyAttributes['inCloneWith'] = true;
	if (count($clonePropertyKeyTypeScalars) === 1) {
		$nodeScopeResolver->processVirtualAssign(
			$scope,
			$storage,
			$stmt,
			new PropertyFetch($cloneExpr, (string) $clonePropertyKeyTypeScalars[0], $propertyAttributes),
			new TypeExpr($clonePropertiesArgTypeConstantArray->getValueTypes()[$i]),
			$nodeCallback,
		);
		continue;
	}

	$nodeScopeResolver->processVirtualAssign(
		$scope,
		$storage,
		$stmt,
		new PropertyFetch($cloneExpr, new TypeExpr($clonePropertyKeyType), $propertyAttributes),
		new TypeExpr($clonePropertiesArgTypeConstantArray->getValueTypes()[$i]),
		$nodeCallback,
	);
}

if ($expr->if === null) {
	$elseResult = $nodeScopeResolver->processExprNode($stmt, $expr->else, $ifFalseScope, $storage, $nodeCallback, $context);
	$throwPoints = array_merge($throwPoints, $elseResult->getThrowPoints());
	$impurePoints = array_merge($impurePoints, $elseResult->getImpurePoints());
	$ifFalseScope = $elseResult->getScope();
} else {
	$ifResult = $nodeScopeResolver->processExprNode($stmt, $expr->if, $ifTrueScope, $storage, $nodeCallback, $context);
	$throwPoints = array_merge($throwPoints, $ifResult->getThrowPoints());
	$impurePoints = array_merge($impurePoints, $ifResult->getImpurePoints());
	$ifTrueScope = $ifResult->getScope();
	$ifTrueType = $ifTrueScope->getType($expr->if);

	$elseResult = $nodeScopeResolver->processExprNode($stmt, $expr->else, $ifFalseScope, $storage, $nodeCallback, $context);
	$throwPoints = array_merge($throwPoints, $elseResult->getThrowPoints());
	$impurePoints = array_merge($impurePoints, $elseResult->getImpurePoints());
	$ifFalseScope = $elseResult->getScope();
}

if (isset($ignoreError['messages'])) {
	foreach ($ignoreError['messages'] as $message) {
		$expandedIgnoreError = $ignoreError;
		unset($expandedIgnoreError['messages']);
		$expandedIgnoreError['message'] = $message;
		$expandedIgnoreErrors[] = $expandedIgnoreError;
	}
} elseif (isset($ignoreError['rawMessages'])) {
	foreach ($ignoreError['rawMessages'] as $rawMessage) {
		$expandedIgnoreError = $ignoreError;
		unset($expandedIgnoreError['rawMessages']);
		$expandedIgnoreError['rawMessage'] = $rawMessage;
		$expandedIgnoreErrors[] = $expandedIgnoreError;
	}
} elseif (isset($ignoreError['identifiers'])) {
	foreach ($ignoreError['identifiers'] as $identifier) {
		$expandedIgnoreError = $ignoreError;
		unset($expandedIgnoreError['identifiers']);
		$expandedIgnoreError['identifier'] = $identifier;
		$expandedIgnoreErrors[] = $expandedIgnoreError;
	}
} else {
	$expandedIgnoreErrors[] = $ignoreError;
}

foreach ($closure->params as $i => $parameter) {
	if (!$parameter->var instanceof Variable || !is_string($parameter->var->name)) {
		throw new ShouldNotHappenException();
	}
	$paramExprString = sprintf('$%s', $parameter->var->name);
	$isNullable = $this->isParameterValueNullable($parameter);
	$nativeParameterType = $parameterType = $this->getFunctionType($parameter->type, $isNullable, $parameter->variadic);
	if ($callableParameters !== null) {
		$parameterType = self::intersectButNotNever($parameterType, $this->getCallableParameterType($parameter, $callableParameters, $i));
	}
	if ($nativeCallableParameters !== null) {
		$nativeParameterType = self::intersectButNotNever($nativeParameterType, $this->getCallableParameterType($parameter, $nativeCallableParameters, $i));
	}
	$expressionTypes[$paramExprString] = ExpressionTypeHolder::createYes($parameter->var, $parameterType);
	$nativeTypes[$paramExprString] = ExpressionTypeHolder::createYes($parameter->var, $nativeParameterType);
}

foreach ($ourNativeExpressionTypes as $exprString => $expressionTypeHolder) {
	if (!array_key_exists($exprString, $theirNativeExpressionTypes)) {
		continue;
	}
	if (!array_key_exists($exprString, $ourExpressionTypes)) {
		continue;
	}
	if (!array_key_exists($exprString, $theirExpressionTypes)) {
		continue;
	}
	if (!$expressionTypeHolder->equals($ourExpressionTypes[$exprString])) {
		continue;
	}
	if (!$theirNativeExpressionTypes[$exprString]->equals($theirExpressionTypes[$exprString])) {
		continue;
	}
	if (!array_key_exists($exprString, $mergedExpressionTypes)) {
		continue;
	}
	$mergedNativeExpressionTypes[$exprString] = $mergedExpressionTypes[$exprString];
	unset($ourNativeExpressionTypes[$exprString]);
	unset($theirNativeExpressionTypes[$exprString]);
}

if (!$conditionType->isTrue()->no()) {
	$exitPoints = $branchScopeStatementResult->getExitPoints();
	$throwPoints = array_merge($throwPoints, $branchScopeStatementResult->getThrowPoints());
	$impurePoints = array_merge($impurePoints, $branchScopeStatementResult->getImpurePoints());
	$branchScope = $branchScopeStatementResult->getScope();
	$finalScope = $branchScopeStatementResult->isAlwaysTerminating() ? null : $branchScope;
	$alwaysTerminating = $branchScopeStatementResult->isAlwaysTerminating();
	if (count($branchScopeStatementResult->getEndStatements()) > 0) {
		$endStatements = array_merge($endStatements, $branchScopeStatementResult->getEndStatements());
	} elseif (count($stmt->stmts) > 0) {
		$endStatements[] = new InternalEndStatementResult($stmt->stmts[count($stmt->stmts) - 1], $branchScopeStatementResult);
	} else {
		$endStatements[] = new InternalEndStatementResult($stmt, $branchScopeStatementResult);
	}
	$hasYield = $branchScopeStatementResult->hasYield() || $hasYield;
}

do {
						$prevScope = $bodyScope;
						$bodyScope = $bodyScope->mergeWith($this->polluteScopeWithAlwaysIterableForeach ? $scope->filterByTruthyValue($arrayComparisonExpr) : $scope);
						$storage = $originalStorage->duplicate();
						$bodyScope = $this->enterForeach($bodyScope, $storage, $originalScope, $stmt, $nodeCallback);
						$bodyScopeResult = $this->processStmtNodesInternal($stmt, $stmt->stmts, $bodyScope, $storage, new NoopNodeCallback(), $context->enterDeep())->filterOutLoopExitPoints();
						$bodyScope = $bodyScopeResult->getScope();
						foreach ($bodyScopeResult->getExitPointsByType(Continue_::class) as $continueExitPoint) {
							$bodyScope = $bodyScope->mergeWith($continueExitPoint->getScope());
						}
						if ($bodyScope->equals($prevScope)) {
							break;
						}

						if ($count >= self::GENERALIZE_AFTER_ITERATION) {
							$bodyScope = $prevScope->generalizeWith($bodyScope);
						}
						$count++;
					} while ($count < self::LOOP_SCOPE_ITERATIONS);

if ($context->isTopLevel()) {
	$count = 0;
	do {
		$prevScope = $bodyScope;
		$bodyScope = $bodyScope->mergeWith($scope);
		$storage = $originalStorage->duplicate();
		$bodyScope = $this->processExprNode($stmt, $stmt->cond, $bodyScope, $storage, new NoopNodeCallback(), ExpressionContext::createDeep())->getTruthyScope();
		$bodyScopeResult = $this->processStmtNodesInternal($stmt, $stmt->stmts, $bodyScope, $storage, new NoopNodeCallback(), $context->enterDeep())->filterOutLoopExitPoints();
		$bodyScope = $bodyScopeResult->getScope();
		foreach ($bodyScopeResult->getExitPointsByType(Continue_::class) as $continueExitPoint) {
			$bodyScope = $bodyScope->mergeWith($continueExitPoint->getScope());
		}
		if ($bodyScope->equals($prevScope)) {
			break;
		}

		if ($count >= self::GENERALIZE_AFTER_ITERATION) {
			$bodyScope = $prevScope->generalizeWith($bodyScope);
		}
		$count++;
	} while ($count < self::LOOP_SCOPE_ITERATIONS);
}

if (count($stmt->cond) > 0) {
	$storage = $originalStorage->duplicate();

	foreach ($stmt->cond as $condExpr) {
		$condResult = $this->processExprNode($stmt, $condExpr, $bodyScope, $storage, new NoopNodeCallback(), ExpressionContext::createDeep());
		$initScope = $condResult->getScope();
		$condResultScope = $condResult->getScope();

		// only the last condition expression is relevant whether the loop continues
		// see https://www.php.net/manual/en/control-structures.for.php
		if ($condExpr === $lastCondExpr) {
			$condTruthiness = ($this->treatPhpDocTypesAsCertain ? $condResultScope->getType($condExpr) : $condResultScope->getNativeType($condExpr))->toBoolean();
			$isIterableAtLeastOnce = $isIterableAtLeastOnce->and($condTruthiness->isTrue());
		}

		$hasYield = $hasYield || $condResult->hasYield();
		$throwPoints = array_merge($throwPoints, $condResult->getThrowPoints());
		$impurePoints = array_merge($impurePoints, $condResult->getImpurePoints());
		$bodyScope = $condResult->getTruthyScope();
	}
}

if (!$argType->isObject()->no()) {
	$nakedReturnType = null;
	if ($nakedMethodReflection !== null) {
		$nakedParametersAcceptor = ParametersAcceptorSelector::selectFromArgs(
			$scope,
			$args,
			$nakedMethodReflection->getVariants(),
			$nakedMethodReflection->getNamedArgumentsVariants(),
		);
		$nakedReturnType = $nakedParametersAcceptor->getReturnType();
	}
	if (
		$nakedReturnType === null
		|| !(new ThisType($nakedMethodReflection->getDeclaringClass()))->isSuperTypeOf($nakedReturnType)->yes()
		|| $nakedMethodReflection->isPure()->no()
	) {
		$this->callNodeCallback($nodeCallback, new InvalidateExprNode($arg->value), $scope, $storage);
		$scope = $scope->invalidateExpression($arg->value, true);
	}
} elseif (!(new ResourceType())->isSuperTypeOf($argType)->no()) {
	$this->callNodeCallback($nodeCallback, new InvalidateExprNode($arg->value), $scope, $storage);
	$scope = $scope->invalidateExpression($arg->value, true);
}

if (time() - $data['lastFullAnalysisTime'] >= 60 * 60 * 24 * $daysOldForSkip) {
	if ($output->isVeryVerbose()) {
		$output->writeLineFormatted(sprintf("Result cache not used because it's more than %d days since last full analysis.", $daysOldForSkip));
	}

	// run full analysis if the result cache is older than X days
	return new ResultCache(
		filesToAnalyse: $allAnalysedFiles,
		fullAnalysis: true,
		lastFullAnalysisTime: time(),
		meta: $meta,
		errors: [],
		locallyIgnoredErrors: [],
		linesToIgnore: [],
		unmatchedLineIgnores: [],
		collectedData: [],
		dependencies: [],
		usedTraitDependencies: [],
		exportedNodes: [],
		projectExtensionFiles: [],
		currentFileHashes: $currentFileHashes,
	);
}

if ($classReflection->hasConstructor()) {
	$methodReflection = $classReflection->getConstructor();
	$asserts = $methodReflection->getAsserts();

	if ($asserts->getAll() !== []) {
		$parametersAcceptor = ParametersAcceptorSelector::selectFromArgs($scope, $expr->getArgs(), $methodReflection->getVariants(), $methodReflection->getNamedArgumentsVariants());

		$asserts = $asserts->mapTypes(static fn (Type $type) => TemplateTypeHelper::resolveTemplateTypes(
			$type,
			$parametersAcceptor->getResolvedTemplateTypeMap(),
			$parametersAcceptor instanceof ExtendedParametersAcceptor ? $parametersAcceptor->getCallSiteVarianceMap() : TemplateTypeVarianceMap::createEmpty(),
			TemplateTypeVariance::createInvariant(),
		));

		$specifiedTypes = $this->specifyTypesFromAsserts($context, $expr, $asserts, $parametersAcceptor, $scope);

		if ($specifiedTypes !== null) {
			return $specifiedTypes;
		}
	}
}

if ($asserts->getAll() !== []) {
	$parametersAcceptor = ParametersAcceptorSelector::selectFromArgs($scope, $expr->getArgs(), $methodReflection->getVariants(), $methodReflection->getNamedArgumentsVariants());

	$asserts = $asserts->mapTypes(static fn (Type $type) => TemplateTypeHelper::resolveTemplateTypes(
		$type,
		$parametersAcceptor->getResolvedTemplateTypeMap(),
		$parametersAcceptor instanceof ExtendedParametersAcceptor ? $parametersAcceptor->getCallSiteVarianceMap() : TemplateTypeVarianceMap::createEmpty(),
		TemplateTypeVariance::createInvariant(),
	));

	$specifiedTypes = $this->specifyTypesFromAsserts($context, $expr, $asserts, $parametersAcceptor, $scope);

	if ($specifiedTypes !== null) {
		return $specifiedTypes;
	}
}

foreach (array_merge(
	$this->container->getServicesByTag(BrokerFactory::PROPERTIES_CLASS_REFLECTION_EXTENSION_TAG),
	$this->container->getServicesByTag(BrokerFactory::METHODS_CLASS_REFLECTION_EXTENSION_TAG),
	$this->container->getServicesByTag(BrokerFactory::DYNAMIC_METHOD_RETURN_TYPE_EXTENSION_TAG),
	$this->container->getServicesByTag(BrokerFactory::DYNAMIC_STATIC_METHOD_RETURN_TYPE_EXTENSION_TAG),
	$this->container->getServicesByTag(BrokerFactory::DYNAMIC_FUNCTION_RETURN_TYPE_EXTENSION_TAG),
	$functionTypeSpecifying,
	$methodTypeSpecifying,
	$staticMethodTypeSpecifying,
) as $extension) {
	if (!($extension instanceof TypeSpecifierAwareExtension)) {
		continue;
	}

	$extension->setTypeSpecifier($typeSpecifier);
}

if ($methodClassReflection->hasMethod($node->name->toString())) {
	$methodReflection = $methodClassReflection->getMethod($node->name->toString(), $scope);
	$this->addClassToDependencies($methodReflection->getDeclaringClass()->getName(), $dependenciesReflections);
	foreach ($methodReflection->getVariants() as $methodVariant) {
		foreach ($methodVariant->getParameters() as $parameter) {
			if ($parameter->getOutType() !== null) {
				foreach ($parameter->getOutType()->getReferencedClasses() as $referencedClass) {
					$this->addClassToDependencies($referencedClass, $dependenciesReflections);
				}
			}
			if ($parameter->getClosureThisType() === null) {
				continue;
			}
			foreach ($parameter->getClosureThisType()->getReferencedClasses() as $referencedClass) {
				$this->addClassToDependencies($referencedClass, $dependenciesReflections);
			}
		}
	}
}

if ($node instanceof Node\Expr\StaticCall && !$node->isFirstClassCallable()) {
	$attributes = $node->getAttributes();
	$origPipeAttributes = $attributes[PipeTransformerVisitor::ORIGINAL_PIPE_ATTRIBUTE_NAME] ?? [];
	$origVariadicPlaceholderAttributes = $attributes[PipeTransformerVisitor::ORIGINAL_VARIADIC_PLACEHOLDER_ATTRIBUTE_NAME] ?? [];
	if ($origPipeAttributes !== [] && count($node->getArgs()) === 1) {
		$origPipeAttributes[self::ARG_ATTRIBUTES_NAME] = $node->getArgs()[0]->getAttributes();
		unset($attributes[PipeTransformerVisitor::ORIGINAL_PIPE_ATTRIBUTE_NAME]);
		unset($attributes[PipeTransformerVisitor::ORIGINAL_VARIADIC_PLACEHOLDER_ATTRIBUTE_NAME]);
		return new Node\Expr\BinaryOp\Pipe(
			$node->getArgs()[0]->value,
			new Node\Expr\StaticCall($node->class, $node->name, [new Node\VariadicPlaceholder($origVariadicPlaceholderAttributes)], attributes: $attributes),
			attributes: $origPipeAttributes,
		);
	}
}

foreach ($tagValue->parameters as $parameterNode) {
	$parameterName = substr($parameterNode->parameterName, 1);
	$type = $parameterNode->type !== null
		? $this->typeNodeResolver->resolve($parameterNode->type, $nameScope)
		: new MixedType();
	if ($parameterNode->defaultValue instanceof ConstExprNullNode) {
		$type = TypeCombinator::addNull($type);
	}
	$defaultValue = null;
	if ($parameterNode->defaultValue !== null) {
		$defaultValue = $this->constExprNodeResolver->resolve($parameterNode->defaultValue, $nameScope);
	}

	$parameters[$parameterName] = new MethodTagParameter(
		$type,
		$parameterNode->isReference
			? PassedByReference::createCreatesNewVariable()
			: PassedByReference::createNo(),
		$parameterNode->isVariadic || $parameterNode->defaultValue !== null,
		$parameterNode->isVariadic,
		$defaultValue,
	);
}

if (!isset($this->properties[$key])) {
	if ($phpClassReflectionExtension->hasProperty($this, $propertyName)) {
		$property = $this->classReflectionExtensionRegistryProvider->getRegistry()->getPhpClassReflectionExtension()->getProperty($this, $propertyName, $scope);
		if ($scope->canReadProperty($property)) {
			return $this->properties[$key] = $property;
		}
		$this->properties[$key] = $property;
	}

	if ($this->allowsDynamicProperties()) {
		foreach ($this->classReflectionExtensionRegistryProvider->getRegistry()->getPropertiesClassReflectionExtensions() as $extension) {
			if (!$extension->hasProperty($this, $propertyName)) {
				continue;
			}

			$property = $this->wrapExtendedProperty($propertyName, $extension->getProperty($this, $propertyName));
			if ($scope->canReadProperty($property)) {
				return $this->properties[$key] = $property;
			}
			$this->properties[$key] = $property;
		}
	}
}

if ($phpDocType !== null) {
	$setHookMethodReflectionVariant = $setHook->getOnlyVariant();
	$setHookMethodReflectionParameters = $setHookMethodReflectionVariant->getParameters();
	if (isset($setHookMethodReflectionParameters[0])) {
		$setHookMethodReflectionParameter = $setHookMethodReflectionParameters[0];
		$setHookMethodReflectionParameterPhpDocType = $setHookMethodReflectionParameter->getPhpDocType();
		if (
			$setHookMethodReflectionParameterPhpDocType instanceof MixedType
			&& !$setHookMethodReflectionParameterPhpDocType instanceof TemplateMixedType
			&& !$setHookMethodReflectionParameterPhpDocType->isExplicitMixed()
		) {
			$setHook = $setHook->changePropertySetHookPhpDocType($setHookMethodReflectionParameter->getName(), $phpDocType);
		}
	}
}

if ($prototype->isPublic()) {
	if (!$constantReflection->isPublic()) {
		$errors[] = RuleErrorBuilder::message(sprintf(
			'%s constant %s::%s overriding public constant %s::%s should also be public.',
			$constantReflection->isPrivate() ? 'Private' : 'Protected',
			$constantReflection->getDeclaringClass()->getDisplayName(false),
			$constantReflection->getName(),
			$prototype->getDeclaringClass()->getDisplayName(false),
			$prototype->getName(),
		))->identifier('classConstant.visibility')->nonIgnorable()->build();
	}
} elseif ($constantReflection->isPrivate()) {
	$errors[] = RuleErrorBuilder::message(sprintf(
		'Private constant %s::%s overriding protected constant %s::%s should be protected or public.',
		$constantReflection->getDeclaringClass()->getDisplayName(false),
		$constantReflection->getName(),
		$prototype->getDeclaringClass()->getDisplayName(false),
		$prototype->getName(),
	))->identifier('classConstant.visibility')->nonIgnorable()->build();
}

if ($parentThrowType->isVoid()->yes()) {
	if ($explicitParentThrowsVoid) {
		$errors[] = RuleErrorBuilder::message(sprintf(
			'Method %s::%s() should not throw %s because parent method %s::%s() has PHPDoc tag @throws void.',
			$method->getDeclaringClass()->getDisplayName(),
			$method->getName(),
			$throwType->describe(VerbosityLevel::typeOnly()),
			$parentMethodDeclaringClass->getDisplayName(),
			$parentMethod->getName(),
		))->identifier('throws.shouldBeVoid')->build();
	} else {
		$errors[] = RuleErrorBuilder::message(sprintf(
			'Method %s::%s() should not throw %s because parent method %s::%s() does not have PHPDoc tag @throws.',
			$method->getDeclaringClass()->getDisplayName(),
			$method->getName(),
			$throwType->describe(VerbosityLevel::typeOnly()),
			$parentMethodDeclaringClass->getDisplayName(),
			$parentMethod->getName(),
		))->identifier('throws.notCovariantWithImplicitVoid')->build();
	}
	continue;
}
